{"content":"use crate::api::*;
use rayon::prelude::*;
use parking_lot::RwLock;
use crate::distance::l2_distance;

pub struct VectorDB {
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>, // Flattened vectors
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != 128 {
            return; // Ignore invalid length for now or handle appropriately
        }
        let mut ids = self.ids.write();
        let mut vectors = self.vectors.write();
        ids.push(id);
        vectors.extend(vector);
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = new_vectors.len();
        let mut ids = self.ids.write();
        let mut vectors = self.vectors.write();

        ids.reserve(count);
        vectors.reserve(count * 128);

        for (id, vec) in new_vectors {
            if vec.len() == 128 {
                ids.push(id);
                vectors.extend(vec);
            }
        }
        count
    }

    pub fn search(&self, query_vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read();
        let vectors = self.vectors.read();

        if ids.is_empty() {
            return Vec::new();
        }

        // Parallel brute force search
        let mut results: Vec<(u64, f64)> = ids.par_iter()
            .enumerate()
            .map(|(i, &id)| {
                let vec_slice = &vectors[i * 128..(i + 1) * 128];
                let dist = l2_distance(query_vector, vec_slice);
                (id, dist)
            })
            .collect();

        // Sort by distance
        // For top_k, we can use a partial sort or select_nth_unstable if k is small relative to N
        // But simple sort is reliable for correctness first.
        results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(std::cmp::Ordering::Equal));

        results.into_iter()
            .take(top_k as usize)
            .map(|(id, dist)| SearchResult { id, distance: dist })
            .collect()
    }
}
