{"path":"src/distance.rs","content":"#[cfg(any(target_arch = "x86", target_arch = "x86_64"))]
use std::arch::x86_64::*;

pub fn l2_distance(a: &[f32], b: &[f32]) -> f64 {
    #[cfg(any(target_arch = "x86", target_arch = "x86_64"))]
    {
        if is_x86_feature_detected!("avx512f") {
            return unsafe { l2_distance_avx512(a, b) };
        } else if is_x86_feature_detected!("avx2") {
            return unsafe { l2_distance_avx2(a, b) };
        }
    }

    l2_distance_scalar(a, b)
}

#[target_feature(enable = "avx512f")]
unsafe fn l2_distance_avx512(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm512_setzero_ps();
    let n = a.len();
    let mut i = 0;

    // Process 16 floats at a time
    while i + 16 <= n {
        let va = _mm512_loadu_ps(a.as_ptr().add(i));
        let vb = _mm512_loadu_ps(b.as_ptr().add(i));
        let diff = _mm512_sub_ps(va, vb);
        sum = _mm512_fmadd_ps(diff, diff, sum);
        i += 16;
    }

    let mut remaining = 0.0;
    if i < n {
         // Create a mask for the remaining elements
         let mask = (1u16 << (n - i)) - 1;
         let va = _mm512_maskz_loadu_ps(mask, a.as_ptr().add(i));
         let vb = _mm512_maskz_loadu_ps(mask, b.as_ptr().add(i));
         let diff = _mm512_sub_ps(va, vb);
         // simple sum for tail since it's masked
         let sq_diff = _mm512_mul_ps(diff, diff);
         remaining = _mm512_reduce_add_ps(sq_diff);
    }

    _mm512_reduce_add_ps(sum) as f64 + remaining as f64
}

#[target_feature(enable = "avx2")]
unsafe fn l2_distance_avx2(a: &[f32], b: &[f32]) -> f64 {
    let mut sum = _mm256_setzero_ps();
    let n = a.len();
    let mut i = 0;

    while i + 8 <= n {
        let va = _mm256_loadu_ps(a.as_ptr().add(i));
        let vb = _mm256_loadu_ps(b.as_ptr().add(i));
        let diff = _mm256_sub_ps(va, vb);
        sum = _mm256_fmadd_ps(diff, diff, sum);
        i += 8;
    }

    let mut total = 0.0;
    // reduce AVX register
    let mut out = [0.0; 8];
    _mm256_storeu_ps(out.as_mut_ptr(), sum);
    total += out.iter().sum::<f32>();

    // finish tail
    while i < n {
        let diff = a[i] - b[i];
        total += diff * diff;
        i += 1;
    }

    total as f64
}

fn l2_distance_scalar(a: &[f32], b: &[f32]) -> f64 {
    a.iter()
     .zip(b.iter())
     .map(|(x, y)| {
         let diff = x - y;
         (diff * diff) as f64
     })
     .sum()
}
"}

{"path":"src/db.rs","content":"use crate::api::*;
use rayon::prelude::*;
use parking_lot::RwLock;
use crate::distance::l2_distance;
use std::cmp::Ordering;
use std::collections::BinaryHeap;

pub struct VectorDB {
    ids: RwLock<Vec<u64>>,
    vectors: RwLock<Vec<f32>>, // Flattened vectors
}

#[derive(PartialEq)]
struct OrderedFloat(f64);

impl Eq for OrderedFloat {}

impl PartialOrd for OrderedFloat {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        self.0.partial_cmp(&other.0)
    }
}

impl Ord for OrderedFloat {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap_or(Ordering::Equal)
    }
}

#[derive(Eq, PartialEq)]
struct HeapItem {
    distance: OrderedFloat,
    id: u64,
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        // Max-heap based on distance (keep smallest distances)
        self.distance.cmp(&other.distance)
    }
}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            ids: RwLock::new(Vec::new()),
            vectors: RwLock::new(Vec::new()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != 128 {
            return; 
        }
        let mut ids = self.ids.write();
        let mut vectors = self.vectors.write();
        ids.push(id);
        vectors.extend(vector);
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = new_vectors.len();
        let mut ids = self.ids.write();
        let mut vectors = self.vectors.write();

        ids.reserve(count);
        vectors.reserve(count * 128);

        for (id, vec) in new_vectors {
            if vec.len() == 128 {
                ids.push(id);
                vectors.extend(vec);
            }
        }
        count
    }

    pub fn search(&self, query_vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        let ids = self.ids.read();
        let vectors = self.vectors.read();

        if ids.is_empty() {
            return Vec::new();
        }

        let k = top_k as usize;

        // Parallel fold-reduce approach
        // Each thread maintains a BinaryHeap of size K (containing the *worst* of the top-k)
        // We use a MaxHeap, so the top is the largest distance.
        // When heap size > k, we pop the max (worst) one.

        let top_k_heap = ids.par_iter()
            .enumerate()
            .fold(
                || BinaryHeap::with_capacity(k + 1),
                |mut heap: BinaryHeap<HeapItem>, (i, &id)| {
                    let vec_slice = &vectors[i * 128..(i + 1) * 128];
                    let dist = l2_distance(query_vector, vec_slice);

                    if heap.len() < k {
                        heap.push(HeapItem { distance: OrderedFloat(dist), id });
                    } else if let Some(max_item) = heap.peek() {
                        if dist < max_item.distance.0 {
                            heap.pop();
                            heap.push(HeapItem { distance: OrderedFloat(dist), id });
                        }
                    }
                    heap
                }
            )
            .reduce(
                || BinaryHeap::with_capacity(k),
                |mut heap1, heap2| {
                    for item in heap2 {
                        if heap1.len() < k {
                            heap1.push(item);
                        } else if let Some(max_item) = heap1.peek() {
                            if item.distance < max_item.distance {
                                heap1.pop();
                                heap1.push(item);
                            }
                        }
                    }
                    heap1
                }
            );

        // Extract sorted results
        let mut results: Vec<SearchResult> = top_k_heap.into_sorted_vec().into_iter()
            .map(|item| SearchResult { id: item.id, distance: item.distance.0 })
            .collect();

        results
    }
}
"}

{"content":"use crate::api::*;
use rayon::prelude::*;
use parking_lot::{RwLock, RwLockUpgradableReadGuard};
use crate::distance::l2_distance;
use std::cmp::Ordering;
use std::collections::BinaryHeap;
use std::sync::atomic::{AtomicBool, Ordering as AtomicOrdering};
use rand::seq::SliceRandom;
use rand::thread_rng;

const NUM_CLUSTERS: usize = 1600; // sqrt(1M) approx
// Need enough probes to hit 95% recall.
// 32/1600 = 2%. With random centroids, might need more.
// Let's create a dynamic config or reasonable default.
const N_PROBE: usize = 64; 

pub struct VectorDB {
    // Staging area for data before indexing
    data: RwLock<Vec<(u64, Vec<f32>)>>,

    // The Index
    index: RwLock<IVFIndex>,
}

#[derive(Default)]
struct IVFIndex {
    built: bool,
    centroids: Vec<Vec<f32>>, // [NUM_CLUSTERS][128]
    // Inverted lists: cluster_id -> (ids, vectors_flat)
    // Flattened vectors for cache locality during scan
    lists: Vec<InvertedList>,
}

#[derive(Default)]
struct InvertedList {
    ids: Vec<u64>,
    vectors: Vec<f32>, // stored flattened: v0_0, v0_1... v1_0...
}

#[derive(PartialEq)]
struct OrderedFloat(f64);

impl Eq for OrderedFloat {}

impl PartialOrd for OrderedFloat {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        self.0.partial_cmp(&other.0)
    }
}

impl Ord for OrderedFloat {
    fn cmp(&self, other: &Self) -> Ordering {
        self.partial_cmp(other).unwrap_or(Ordering::Equal)
    }
}

#[derive(Eq, PartialEq)]
struct HeapItem {
    distance: OrderedFloat,
    id: u64,
}

impl Ord for HeapItem {
    fn cmp(&self, other: &Self) -> Ordering {
        self.distance.cmp(&other.distance)
    }
}

impl PartialOrd for HeapItem {
    fn partial_cmp(&self, other: &Self) -> Option<Ordering> {
        Some(self.cmp(other))
    }
}

impl VectorDB {
    pub fn new() -> Self {
        VectorDB {
            data: RwLock::new(Vec::new()),
            index: RwLock::new(IVFIndex::default()),
        }
    }

    pub fn insert(&self, id: u64, vector: Vec<f32>) {
        if vector.len() != 128 { return; }
        self.data.write().push((id, vector));
    }

    pub fn bulk_insert(&self, new_vectors: Vec<(u64, Vec<f32>)>) -> usize {
        let count = new_vectors.len();
        let mut data = self.data.write();
        for (id, vec) in new_vectors {
            if vec.len() == 128 {
                data.push((id, vec));
            }
        }
        count
    }

    fn train_and_build(&self) {
        // This function upgrades the lock and builds the index
        let upgradeable_index = self.index.upgradable_read();

        if upgradeable_index.built {
            return;
        }

        let mut data_lock = self.data.write();
        // Since we are moving data to index, we consume it.
        // Wait, if we clear data, subsequent inserts are fine.
        // But we need to handle "data already in index" vs "new data".
        // Simplest: take all data out of `data`, build index.
        // If query comes, check new data in `data` (which is empty) + index.

        if data_lock.is_empty() {
            return;
        }

        // Upgrade to write lock
        let mut index_lock = RwLockUpgradableReadGuard::upgrade(upgradeable_index);

        let total_vecs = data_lock.len();
        // println!("Building index for {} vectors...", total_vecs);

        // 1. Train Centroids (use subset if large)
        let num_clusters = NUM_CLUSTERS;
        let mut rng = thread_rng();
        let sample_size = std::cmp::min(total_vecs, 50_000);
        let mut sample_indices: Vec<usize> = (0..total_vecs).collect();
        sample_indices.shuffle(&mut rng);

        // Initialize centroids with random points
        let mut centroids: Vec<Vec<f32>> = (0..num_clusters)
            .map(|i| data_lock[sample_indices[i % total_vecs]].1.clone())
            .collect();

        // K-Means iterations (e.g. 5)
        for _iter in 0..5 {
            // Assign sample points to nearest centroid and accumulate sum
            // This is slow if done strictly.
            // Let's do a simplified one-shot or just stick to random if we are lazy?
            // K-Means significantly improves quantization quality.
            // We can paralellize the assignment step.

            // Just use the initial random centroids for now to test pipeline?
            // "Random projection" is robust enough for high recall if N_PROBE is high enough.
            // Let's skipping full K-Means loop for first iteration to see speed.
            // Actually, static random centroids from data distribution is a decent baseline.
            // Let's refine centroids *once*?
            // Let's do one pass of refinement on the sample.

            let mut new_centroids = vec![vec![0.0f32; 128]; num_clusters];
            let mut counts = vec![0u32; num_clusters];

            // Assign sample subset
            let samples: Vec<&Vec<f32>> = sample_indices.iter().take(sample_size).map(|&i| &data_lock[i].1).collect();

            // Parallelize assignment
             let assignments: Vec<(usize, usize)> = samples.par_iter().enumerate().map(|(idx, vec)| {
                let mut best_dist = f64::MAX;
                let mut best_c = 0;
                for (c_idx, c_vec) in centroids.iter().enumerate() {
                    let d = l2_distance(vec, c_vec);
                    if d < best_dist {
                        best_dist = d;
                        best_c = c_idx;
                    }
                }
                (idx, best_c)
             }).collect();

             for (s_idx, c_idx) in assignments {
                 let s_vec = samples[s_idx];
                 for k in 0..128 {
                     new_centroids[c_idx][k] += s_vec[k];
                 }
                 counts[c_idx] += 1;
             }

             for c in 0..num_clusters {
                 if counts[c] > 0 {
                     let inv = 1.0 / counts[c] as f32;
                     for k in 0..128 {
                         centroids[c][k] = new_centroids[c][k] * inv;
                     }
                 }
             }
        }

        index_lock.centroids = centroids;
        index_lock.lists = (0..num_clusters).map(|_| InvertedList::default()).collect();

        // 2. Assign all data to centroids
        let assignments: Vec<usize> = data_lock.par_iter().map(|(_, vec)| {
            let mut best_dist = f64::MAX;
            let mut best_c = 0;
            // Scan all centroids
            for (c_idx, c_vec) in index_lock.centroids.iter().enumerate() {
                let d = l2_distance(vec, c_vec);
                if d < best_dist {
                    best_dist = d;
                    best_c = c_idx;
                }
            }
            best_c
        }).collect();

        // 3. Populate lists
        for (i, cluster_idx) in assignments.into_iter().enumerate() {
            let (id, vec) = &data_lock[i];
            index_lock.lists[cluster_idx].ids.push(*id);
            index_lock.lists[cluster_idx].vectors.extend_from_slice(vec);
        }

        index_lock.built = true;
        // Clear staged data
        data_lock.clear();
    }

    pub fn search(&self, query_vector: &[f32], top_k: u32) -> Vec<SearchResult> {
        // Heuristic: if we have a lot of data in staging, maybe build index?
        // Check without lock first
        let data_len = self.data.read().len();
        if data_len > 10_000 {
           self.train_and_build();
        }

        let index = self.index.read();
        let staging = self.data.read(); // Read lock for fallback search

        if !index.built {
            // Brute force on staging
            if staging.is_empty() {
                return Vec::new();
            }
             let mut results: Vec<(u64, f64)> = staging.par_iter()
                .map(|(id, vec)| {
                    (*id, l2_distance(query_vector, vec))
                })
                .collect();
            // Partial sort top_k
            if top_k as usize >= results.len() {
                 results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal));
            } else {
                 results.select_nth_unstable_by(top_k as usize, |a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal));
                 results.truncate(top_k as usize);
                 results.sort_by(|a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal));
            }
            return results.into_iter().map(|(id, d)| SearchResult{id, distance: d}).collect();
        }

        // IVF Search

        // 1. Find nearest centroids (coarse search)
        // This is small (1600 centroids), single thread is fine or rayon?
        // 1600 * 128 distance calcs is fast.
        let mut centroid_dists: Vec<(usize, f64)> = index.centroids.iter()
            .enumerate()
            .map(|(i, c)| (i, l2_distance(query_vector, c)))
            .collect();

        // sort ascending
        // We need top N_PROBE
        if N_PROBE < centroid_dists.len() {
             centroid_dists.select_nth_unstable_by(N_PROBE, |a, b| a.1.partial_cmp(&b.1).unwrap_or(Ordering::Equal));
             centroid_dists.truncate(N_PROBE);
        }

        // 2. Search in candidate lists
        let k = top_k as usize;

        // We can collect all candidate vectors and do a bulk search, 
        // or search list by list and merge heaps.

        let candidates: Vec<&InvertedList> = centroid_dists.iter()
            .map(|(idx, _)| &index.lists[*idx])
            .collect();

        // Use a thread-local heap approach via Rayon `fold` + `reduce` over the lists?
        // Or flattener?
        // N_PROBE lists. Some might be empty.

        let top_k_heap = candidates.into_par_iter()
            .fold(
                || BinaryHeap::with_capacity(k + 1),
                |mut heap, list| {
                    let n = list.ids.len();
                    for i in 0..n {
                        let vec_slice = &list.vectors[i*128..(i+1)*128];
                        let dist = l2_distance(query_vector, vec_slice);

                         if heap.len() < k {
                            heap.push(HeapItem { distance: OrderedFloat(dist), id: list.ids[i] });
                        } else if let Some(max_item) = heap.peek() {
                            if dist < max_item.distance.0 {
                                heap.pop();
                                heap.push(HeapItem { distance: OrderedFloat(dist), id: list.ids[i] });
                            }
                        }
                    }
                    heap
                }
            )
            .reduce(
                 || BinaryHeap::with_capacity(k),
                 |mut heap1, heap2| {
                    for item in heap2 {
                        if heap1.len() < k {
                            heap1.push(item);
                        } else if let Some(max_item) = heap1.peek() {
                             if item.distance < max_item.distance {
                                heap1.pop();
                                heap1.push(item);
                            }
                        }
                    }
                    heap1
                 }
            );

         // Also check staging area! (newly inserted vectors)
         // Usually small, but required for consistency
         let final_heap = staging.iter().fold(top_k_heap, |mut heap, (id, vec)| {
              let dist = l2_distance(query_vector, vec);
               if heap.len() < k {
                    heap.push(HeapItem { distance: OrderedFloat(dist), id: *id });
                } else if let Some(max_item) = heap.peek() {
                    if dist < max_item.distance.0 {
                        heap.pop();
                        heap.push(HeapItem { distance: OrderedFloat(dist), id: *id });
                    }
                }
                heap
         });

        let mut results: Vec<SearchResult> = final_heap.into_sorted_vec().into_iter()
            .map(|item| SearchResult { id: item.id, distance: item.distance.0 })
            .collect();

        results
    }
}
